; Sideways ROM header
; ANFS ROM 4.08.53 disassembly (Acorn Advanced Network Filing System)
; ===================================================================
.pydis_start
.rom_header
.language_entry
rom_header_byte1 = rom_header+1
rom_header_byte2 = rom_header+2
    equb 0, &42, &43                                                  ; 8000: 00 42 43    .BC

.service_entry
    jmp service_handler                                               ; 8003: 4c 54 8a    LT.            ; JMP service_handler

.rom_type
    equb &82                                                          ; 8006: 82          .              ; ROM type: service + language
.copyright_offset
    equb copyright - rom_header                                       ; 8007: 19          .
.binary_version
    equb 4                                                            ; 8008: 04          .
.title
    equs "Acorn ANFS 4.21"                                            ; 8009: 41 63 6f... Aco
.version
    equb 0                                                            ; 8018: 00          .
.copyright
    equb 0                                                            ; 8019: 00          .              ; Null terminator before copyright
.copyright_string
    equs "(C)1986 Acorn", 0                                           ; 801a: 28 43 29... (C)

; ***************************************************************************************
; Service 5: unrecognised interrupt (Master 128 dispatch)
; 
; Reads the deferred-work flag at &0D65; if zero, returns early via PLX/PLY/RTS.
; Otherwise clears bit 7 of the Master 128 ACCCON register at &FE34 (TRB), zeros &0D65,
; then dispatches either via the PHA/PHA/RTS table at dispatch_svc5 (&8048) when Y had
; bit 7 set on entry, or fires Econet RX event &FE via generate_event and JMPs to &8582
; (post-event handler).
; 
; Note: 4.18's equivalent at the same address tested VIA IFR bit 2 for shift-register
; completion; the 4.21 version is rewritten around the Master 128's deferred-work flag
; pattern. Detailed re-annotation deferred.
; 
; On Entry:
;     A: 5 (service call number)
;     X: ROM slot
;     Y: parameter (high bit selects dispatch path)
; ***************************************************************************************
.svc5_irq_check
    phx                                                               ; 8028: da          .
    phy                                                               ; 8029: 5a          Z
    ldy tx_op_type                                                    ; 802a: ac 65 0d    .e.
    bne c8032                                                         ; 802d: d0 03       ..             ; SR set: shift register complete
    ply                                                               ; 802f: 7a          z
    plx                                                               ; 8030: fa          .
    rts                                                               ; 8031: 60          `

; &8032 referenced 1 time by &802d
.c8032
    lda #&80                                                          ; 8032: a9 80       ..             ; A=5: not our interrupt, pass on
    trb lfe34                                                         ; 8034: 1c 34 fe    .4.
    stz tx_op_type                                                    ; 8037: 9c 65 0d    .e.
    tya                                                               ; 803a: 98          .              ; Copy to A for sign test
    bmi dispatch_svc5                                                 ; 803b: 30 0b       0.             ; Bit 7 set: dispatch via table
    lda #&fe                                                          ; 803d: a9 fe       ..             ; A=&FE: Econet receive event
    jsr generate_event                                                ; 803f: 20 45 80     E.            ; Call event vector handler
    jmp tx_done_exit                                                  ; 8042: 4c 82 85    L..            ; Fire event (enable: *FX52,150)

; ***************************************************************************************
; Generate event via event vector
; 
; Dispatches through the event vector (EVNTV)
; to notify event handlers. Called with the event
; number in A.
; 
; On Entry:
;     A: event number
; 
; On Exit:
;     A: preserved
;     X: preserved
;     Y: preserved
; ***************************************************************************************
; &8045 referenced 1 time by &803f
.generate_event
    jmp (evntv)                                                       ; 8045: 6c 20 02    l .            ; Dispatch through event vector

; &8048 referenced 1 time by &803b
.dispatch_svc5
    lda #&85                                                          ; 8048: a9 85       ..             ; Push return addr high (&85)
    pha                                                               ; 804a: 48          H              ; High byte on stack for RTS
    lda l84b8,y                                                       ; 804b: b9 b8 84    ...            ; Load dispatch target low byte
    pha                                                               ; 804e: 48          H              ; Low byte on stack for RTS
.svc_5_unknown_irq
    rts                                                               ; 804f: 60          `              ; RTS = dispatch to PHA'd address

; ***************************************************************************************
; ADLC initialisation
; 
; Initialise ADLC hardware and Econet workspace.
; Reads station ID via &FE18 (INTOFF side effect),
; performs a full ADLC reset (adlc_full_reset), then
; checks for Tube co-processor via OSBYTE &EA and
; stores the result in l0d63. Issues NMI claim service
; request (OSBYTE &8F, X=&0C). Falls through to
; init_nmi_workspace to copy the NMI shim to RAM.
; ***************************************************************************************
; &8050 referenced 1 time by &903c
.adlc_init
    bit lfe38                                                         ; 8050: 2c 38 fe    ,8.            ; INTOFF: read station ID, disable NMIs
    jsr adlc_full_reset                                               ; 8053: 20 8c 89     ..            ; Full ADLC hardware reset
    lda #&ea                                                          ; 8056: a9 ea       ..             ; OSBYTE &EA: check Tube co-processor
    ldx #0                                                            ; 8058: a2 00       ..             ; X=0 for OSBYTE
    stx econet_init_flag                                              ; 805a: 8e 62 0d    .b.            ; Clear Econet init flag before setup
    jsr osbyte_x0                                                     ; 805d: 20 c9 8e     ..            ; Check Tube presence via OSBYTE &EA
    stx tube_present                                                  ; 8060: 8e 63 0d    .c.            ; Store Tube presence flag from OSBYTE &EA
    lda #&8f                                                          ; 8063: a9 8f       ..             ; OSBYTE &8F: issue service request
    ldx #&0c                                                          ; 8065: a2 0c       ..             ; X=&0C: NMI claim service
    jsr osbyte_yff                                                    ; 8067: 20 cb 8e     ..            ; Issue NMI claim service request
    ldy #5                                                            ; 806a: a0 05       ..             ; Y=5: NMI claim service number
.econet_restore
    cpy #5                                                            ; 806c: c0 05       ..             ; Check if NMI service was claimed (Y changed)
    bne adlc_init_done                                                ; 806e: d0 2a       .*             ; Service claimed by other ROM: skip init
; ***************************************************************************************
; Initialise NMI workspace (skip service request)
; 
; Copies 32 bytes of NMI shim code from ROM
; (listen_jmp_hi) to &0D00, then patches the current
; ROM bank number into the self-modifying code at
; &0D07. The shim includes the INTOFF/INTON pair
; (BIT &FE18 at entry, BIT &FE20 before RTI) that
; toggles the IC97 NMI enable flip-flop to guarantee
; edge re-triggering on /NMI. Clears tx_src_net,
; need_release_tube, and tx_op_type to zero. Reads
; station ID into tx_src_stn (&0D22). Sets
; tx_complete_flag and econet_init_flag to &80.
; Finally re-enables NMIs via INTON (&FE20 read).
; ***************************************************************************************
.init_nmi_workspace
    ldy #&20 ; ' '                                                    ; 8070: a0 20       .              ; Copy 32 bytes of NMI shim from ROM to &0D00
; &8072 referenced 1 time by &8079
.copy_nmi_shim
    lda l89c9,y                                                       ; 8072: b9 c9 89    ...            ; Read byte from NMI shim ROM source
    sta l0cff,y                                                       ; 8075: 99 ff 0c    ...            ; Write to NMI shim RAM at &0D00
    dey                                                               ; 8078: 88          .              ; Next byte (descending)
    bne copy_nmi_shim                                                 ; 8079: d0 f7       ..             ; Loop until all 32 bytes copied
    lda romsel_copy                                                   ; 807b: a5 f4       ..             ; Patch current ROM bank into NMI shim
    sta nmi_romsel                                                    ; 807d: 8d 07 0d    ...            ; Self-modifying code: ROM bank at &0D07
    sty tx_src_net                                                    ; 8080: 8c 23 0d    .#.            ; Clear source network (Y=0 from copy loop)
    sty prot_flags                                                    ; 8083: 84 99       ..             ; Clear Tube release flag
    sty tx_op_type                                                    ; 8085: 8c 65 0d    .e.            ; Clear TX operation type
    ldy #1                                                            ; 8088: a0 01       ..
    lda (net_rx_ptr),y                                                ; 808a: b1 9c       ..
    sta tx_src_stn                                                    ; 808c: 8d 22 0d    .".
    lda #&80                                                          ; 808f: a9 80       ..             ; &80 = Econet initialised
    sta tx_complete_flag                                              ; 8091: 8d 60 0d    .`.            ; Mark TX as complete (ready)
    sta econet_init_flag                                              ; 8094: 8d 62 0d    .b.            ; Mark Econet as initialised
    bit lfe3c                                                         ; 8097: 2c 3c fe    ,<.            ; INTON: re-enable NMIs (&FE20 read side effect)
; &809a referenced 1 time by &806e
.adlc_init_done
    rts                                                               ; 809a: 60          `              ; Return

; ***************************************************************************************
; NMI RX scout handler (initial byte)
; 
; Default NMI handler for incoming scout frames. Checks if the frame
; is addressed to us or is a broadcast. Installed as the NMI target
; during idle RX listen mode.
; Tests SR2 bit0 (AP = Address Present) to detect incoming data.
; Reads the first byte (destination station) from the RX FIFO and
; compares against our station ID. Reading &FE18 also disables NMIs
; (INTOFF side effect).
; ***************************************************************************************
; &809b referenced 1 time by &89d5
.nmi_rx_scout
    lda #1                                                            ; 809b: a9 01       ..             ; A=&01: mask for SR2 bit0 (AP = Address Present)
    bit econet_control23_or_status2                                   ; 809d: 2c a1 fe    ,..            ; BIT SR2: Z = A AND SR2 -- tests if AP is set
    beq scout_error                                                   ; 80a0: f0 36       .6             ; AP not set, no incoming data -- check for errors
    lda econet_data_continue_frame                                    ; 80a2: ad a2 fe    ...            ; Read first RX byte (destination station address)
    cmp tx_src_stn                                                    ; 80a5: cd 22 0d    .".            ; Compare to our station ID (&FE18 read = INTOFF, disables NMIs)
    beq accept_frame                                                  ; 80a8: f0 09       ..             ; Match -- accept frame
    cmp #&ff                                                          ; 80aa: c9 ff       ..             ; Check for broadcast address (&FF)
    bne scout_reject                                                  ; 80ac: d0 18       ..             ; Neither our address nor broadcast -- reject frame
    lda #&40 ; '@'                                                    ; 80ae: a9 40       .@             ; Flag &40 = broadcast frame
    sta rx_src_net                                                    ; 80b0: 8d 3e 0d    .>.            ; Store broadcast flag in rx_src_net
; &80b3 referenced 1 time by &80a8
.accept_frame
    lda #&b8                                                          ; 80b3: a9 b8       ..             ; Install nmi_rx_scout_net NMI handler
    jmp install_nmi_handler                                           ; 80b5: 4c 11 0d    L..            ; Install next handler and RTI

; ***************************************************************************************
; RX scout second byte handler
; 
