    equb &0a                                                          ; b0d6: 0a          .              ; Index 2: threshold 10 (default)
    equb &14                                                          ; b0d7: 14          .              ; Index 3: threshold 20
    equb &1d                                                          ; b0d8: 1d          .
    equb &27                                                          ; b0d9: 27          '              ; Padding
